def encode(message, encoding_type='default'):
    """
    Write a function that takes a message, and encodes it in such a 
    way that it swaps the case of all letters, replaces all vowels in 
    the message with the letter that appears 2 places ahead of that 
    vowel in the English alphabet. 
    Assume only letters. 

    The `encoding_type` parameter allows for different vowel encoding styles.

    Examples:
    >>> encode('test')
    'TGST'
    >>> encode('This is a message')
    'tHKS KS C MGSSCGG'
    >>> encode('Hello World', encoding_type='shift')
    'Jgnnq Yqtnf'
    """

    def encode_vowel(char):
        if char.lower() in 'aeiou':
            return chr(ord(char) + 2)
        return char

    encoded_message = []
    for char in message:
        if char.isalpha():
            if encoding_type == 'shift' and char.lower() in 'aeiou':
                new_char = encode_vowel(char)
            else:
                new_char = char.swapcase()
            encoded_message.append(new_char)
        else:
            encoded_message.append(char)

    return ''.join(encoded_message)
